def lcs(X, Y):
    m = len(X)
    n = len(Y)

    # dp[i][j] stores the length of the LCS of X[0...i-1] and Y[0...j-1]
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Fill dp table in a bottom-up manner
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if X[i-1] == Y[j-1]:
                dp[i][j] = 1 + dp[i-1][j-1]
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])

    # Reconstruct the LCS string
    # Start from the bottom-right corner of the dp table
    index = dp[m][n]
    lcs_string = [""] * (index + 1) # Create a list to store the LCS characters

    i = m
    j = n
    while i > 0 and j > 0:
        if X[i-1] == Y[j-1]:
            # If current characters are same, they are part of LCS
            lcs_string[index - 1] = X[i-1]
            i -= 1
            j -= 1
            index -= 1
        elif dp[i-1][j] > dp[i][j-1]:
            # If not same, move to the direction of the larger value
            # This means X[i-1] was not part of the LCS
            i -= 1
        else:
            # This means Y[j-1] was not part of the LCS
            j -= 1

    return "".join(lcs_string)
